  trackEvent("begin_checkout", { currency: "PYG", value: total })
}

export function trackPurchase(order: { id: string; total: number; items: { name: string; price: number; quantity: number }[] }) {
  trackEvent("purchase", {
    transaction_id: order.id,
    value: order.total,
    currency: "PYG",
